// mapColorFor returns the vanilla base map color id (0-61) for a block
// state id; 0 means no color (transparent on maps).
func mapColorFor(state uint32) uint8 {
	lo, hi := 0, len(mapColorRanges)-1
	for lo <= hi {
		mid := int(uint(lo+hi) >> 1)
		r := mapColorRanges[mid]
		switch {
		case state < r.base:
			hi = mid - 1
		case state >= r.base+r.count:
			lo = mid + 1
		default:
			return r.color
		}
	}
	return 0
}
